 1	import type { FC } from 'react';
 2	
 3	import { Card, CardBody, CardHeader, CardTitle, Flex, FlexItem } from '@patternfly/react-core';
 4	import { TELEMETRY_EVENTS, TipsTopicSourceComponent } from '@utils/analytics/constants';
 5	import { useForkliftAnalytics } from '@utils/analytics/hooks/useForkliftAnalytics';
 6	
 7	import type { LearningExperienceTopic } from './types';
 8	
 9	type LearningTopicsCardsProps = {
10	  topics: LearningExperienceTopic[];
11	  onSelect: (learningTopic: LearningExperienceTopic) => void;
12	};
13	
14	const LearningTopicsCards: FC<LearningTopicsCardsProps> = ({ onSelect, topics }) => {
15	  const { trackEvent } = useForkliftAnalytics();
16	
17	  return (
18	    <Flex direction={{ default: 'column' }} spacer={{ default: 'spacerMd' }}>
19	      {topics.map((learningExperienceTopic) => (
20	        <FlexItem key={learningExperienceTopic.id}>
21	          <Card
22	            id={learningExperienceTopic.id}
23	            isClickable
24	            isRounded
25	            onClick={() => {
26	              trackEvent(TELEMETRY_EVENTS.TIPS_AND_TRICKS_VISITED, {
27	                componentType: TipsTopicSourceComponent.TipsTopicCard,
28	                helpTopic: learningExperienceTopic.trackingEventTopic,
29	              });
30	              onSelect(learningExperienceTopic);
31	            }}
32	          >
33	            <CardHeader
34	              selectableActions={{
35	                name: learningExperienceTopic.id,
36	                selectableActionAriaLabelledby: learningExperienceTopic.id,
37	                selectableActionId: learningExperienceTopic.id,
38	              }}
39	            >
40	              <CardTitle>
41	                <Flex>
42	                  <FlexItem className="pf-v6-u-mr-sm">{learningExperienceTopic.icon}</FlexItem>
43	                  <FlexItem>{learningExperienceTopic.title}</FlexItem>
44	                </Flex>
45	              </CardTitle>
46	            </CardHeader>
47	            <CardBody className="pf-v6-u-ml-lg">{learningExperienceTopic.description}</CardBody>
48	          </Card>
49	        </FlexItem>
50	      ))}
51	    </Flex>
52	  );
53	};
54	
55	export default LearningTopicsCards;

